// ── 比特浏览器窗口管理 ───────────────────────────────────────────────────────

export async function GetBrowserWindows() {
  await delay()
  return MOCK_BROWSER_WINDOWS
}

export async function AddBrowserWindow(profileId, name) {
  await delay(800)
  const seq = MOCK_BROWSER_WINDOWS.length + 1
  MOCK_BROWSER_WINDOWS.push({
    id: profileId,
    name,
    seq,
    conn_status: 'connected',
    login_status: 'unknown',
    cookie_updated_at: '',
    enabled: true,
    created_at: new Date().toISOString(),
  })
  return null
}

export async function TestBrowserWindow(profileId) {
  await delay(1200)
  // Stub: always succeeds in dev mode
  // In production, pings BitBrowser API to verify window exists
  return { online: true }
}

export async function CheckWindowLogin(profileId) {
  await delay(1500)
  // Stub (POC): returns valid to simulate a logged-in window.
  // Production: CDP WS → read sessionid cookies → call Douyin IM user info API.
  const w = MOCK_BROWSER_WINDOWS.find(x => x.id === profileId)
  if (w) w.login_status = 'valid'
  return { status: 'valid', message: 'Cookie 检测通过（POC 模式）' }
}

export async function UpdateWindowName(profileId, name) {
  await delay(300)
  const w = MOCK_BROWSER_WINDOWS.find(x => x.id === profileId)
  if (w) w.name = name
  return null
}

export async function DeleteBrowserWindow(profileId) {
  await delay(300)
  const w = MOCK_BROWSER_WINDOWS.find(x => x.id === profileId)
  if (w) w.enabled = false
  return null
}

