// ── 私信账号（从窗口管理派生）──────────────────────────────────────────────

export async function GetAccounts(page = 1, pageSize = 6) {
  await delay()
  // Derive account list from browser windows for binding selectors
  const profiles = MOCK_BROWSER_WINDOWS
    .filter(w => w.enabled)
    .map(w => ({
      seq: w.seq,
      profile_id: w.id,
      display_name: w.name,
      douyin_uid: '',
      nickname: w.name,
      cookie_status: w.login_status === 'valid' ? 'valid' : w.login_status === 'expired' ? 'expired' : 'unknown',
      cookie_updated_at: w.cookie_updated_at,
      test_passed: w.conn_status === 'connected',
      enabled: w.enabled,
      daily_dm_sent: 0,
      daily_dm_limit: 100,
      consecutive_failures: 0,
    }))
  return paged(profiles, page, pageSize)
}

