export async function GetLogs(level = '', keyword = '', page = 1, pageSize = 11) {
  await delay()
  let filtered = MOCK_SYSTEM_LOGS
  if (level) filtered = filtered.filter(l => l.level === level)
  if (keyword) filtered = filtered.filter(l => l.message.includes(keyword))
  return paged(filtered, page, pageSize)
}

